const express = require('express');
const { MongoClient } = require('mongodb');

const app = express();
app.use(express.json()); // Middleware to parse JSON bodies

// MongoDB connection URI
const MONGODB_URI = 'mongodb://localhost:27017'; // Replace with your MongoDB URI
const DB_NAME = 'yourDatabaseName'; // Replace with your database name
const COLLECTION_NAME = 'yourCollectionName'; // Replace with your collection name

let db;

// Connect to MongoDB once when the server starts
MongoClient.connect(MONGODB_URI, { useNewUrlParser: true, useUnifiedTopology: true })
    .then(client => {
        db = client.db(DB_NAME);
        console.log(`Connected to MongoDB database: ${DB_NAME}`);
    })
    .catch(err => {
        console.error('Failed to connect to MongoDB', err);
        process.exit(1); // Exit the process if MongoDB connection fails
    });

// API endpoint to query MongoDB
app.post('/query', async (req, res) => {
    if (!db) {
        return res.status(500).json({ error: 'Database not connected.' });
    }

    const { filter = {}, projection = {}, sort = {}, skip = 0, limit = 0 } = req.body;

    try {
        const collection = db.collection(COLLECTION_NAME);

        let cursor = collection.find(filter);

        if (Object.keys(projection).length > 0) {
            cursor = cursor.project(projection);
        }

        if (Object.keys(sort).length > 0) {
            cursor = cursor.sort(sort);
        }

        if (skip > 0) {
            cursor = cursor.skip(skip);
        }

        if (limit > 0) {
            cursor = cursor.limit(limit);
        }

        const results = await cursor.toArray();
        res.status(200).json(results);
    } catch (error) {
        console.error('MongoDB query error:', error);
        res.status(500).json({ error: 'Failed to execute query.', details: error.message });
    }
});

// Start the Express server
const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
    console.log(`Server is running on port ${PORT}`);
    console.log(`Endpoint: POST http://localhost:${PORT}/query`);
});